def tr(html, pairs):
    for a, b in pairs:
        html = html.replace(a, b)
    return html

def fix_paths(html, lang):
    html = html.replace('href="blog/', 'href="../blog/')
    html = html.replace('href="index.html"', 'href="../index.html"')
    html = html.replace('href="ar/index.html"', 'href="../ar/index.html"')
    html = html.replace('href="es/index.html"', 'href="../es/index.html"')
    html = html.replace('href="pt/index.html"', 'href="../pt/index.html"')
    html = html.replace('href="en/index.html"', 'href="../en/index.html"')
    html = html.replace('href="../' + lang + '/index.html"', 'href="index.html"')
    return html

